    private void operator_equalsActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_operator_equalsActionPerformed
        String expressao = result.getText();
        if (expressao.isEmpty()) return;

        try {
            String[] tokens = expressao.split("(?<=[-+*/])|(?=[-+*/])");
            
            java.util.List<Double> numeros = new java.util.ArrayList<>();
            java.util.List<String> operadores = new java.util.ArrayList<>();

            for (String t : tokens) {
                String token = t.trim();
                if (token.isEmpty()) continue;
                if ("+-*/".contains(token)) {
                    operadores.add(token);
                } else {
                    numeros.add(Double.parseDouble(token));
                }
            }

            for (int i = 0; i < operadores.size(); i++) {
                String op = operadores.get(i);
                if (op.equals("*") || op.equals("/")) {
                    double n1 = numeros.get(i);
                    double n2 = numeros.get(i + 1);
                    double res = op.equals("*") ? n1 * n2 : n1 / n2;
                    
                    numeros.set(i, res);
                    numeros.remove(i + 1);
                    operadores.remove(i);
                    i--;
                }
            }

            double resultadoFinal = numeros.get(0);
            for (int i = 0; i < operadores.size(); i++) {
                String op = operadores.get(i);
                double proximoNum = numeros.get(i + 1);
                if (op.equals("+")) resultadoFinal += proximoNum;
                if (op.equals("-")) resultadoFinal -= proximoNum;
            }

            if (resultadoFinal == (long) resultadoFinal) {
                result.setText(String.format("%d", (long) resultadoFinal));
            } else {
                result.setText(String.format("%.2f", resultadoFinal).replace(",", "."));
            }

        } catch (Exception e) {
            result.setText("Erro");
        }
    }//GEN-LAST:event_operator_equalsActionPerformed

