    private void clear_charactereActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_clear_charactereActionPerformed
        removerCaractereResultado();
    }//GEN-LAST:event_clear_charactereActionPerformed

    private void adicionarNumeroAoResultado(String numero){
        result.setText(result.getText() + numero);
    }
    
    private void adicionarOperadorAoResultado(String operador) {
        String operadores = "+-*/";
        String ultimo = getLastCharacter();

        if (!ultimo.isEmpty() && !operadores.contains(ultimo)) {
            result.setText(result.getText() + operador);
        } else if (!ultimo.isEmpty()) {
            String textoBase = result.getText().trim();
            textoBase = textoBase.substring(0, textoBase.length() - 1);
            result.setText(textoBase + operador);
        }
    }

    private String getLastCharacter() {
        String text = result.getText().trim();
        if (text.length() > 0) {
            return text.substring(text.length() - 1);
        }
        return "";
    }
    
    private void removerCaractereResultado(){
        String text = result.getText();
        if (text.length() > 0) {
            result.setText(text.substring(0, text.length() - 1));
        }
    }
    
